sql:
SELECT topology_name, description
FROM network_topologies
WHERE topology_type = 'star' AND description LIKE '%spread%';

SELECT uav_name, manufacturer
FROM uavs
WHERE max_speed > 100.0 AND battery_life < 5.0;

SELECT uav_name, model, manufacturer 
FROM uavs
WHERE uav_id = 0;

SELECT COUNT(*) 
FROM uav_communications 
WHERE communication_type = 'video';

SELECT comm_id, sim_id
FROM uav_communications
WHERE sender_state = 1;

external_knowledge:
'finished urban test scenarios' refers to simulations with 'Urban' type and 'Completed' status;
'communicated using data' means the communication type is 'Data';
'names' refers to the UAV names;
'current locations' refers to the current position of the UAVs;
'condition of their communicators' refers to the sender state;
'operational status' refers to the state name of the sender states.

sql:
SELECT uav_id, AVG(data_transmission_rate) AS average_transmission_rate
FROM uav_communications
GROUP BY uav_id;

SELECT ROW_NUMBER() OVER (ORDER BY sim_id) AS row_num, sim_id, simulation_type, simulation_status
FROM simulations
WHERE network_topology = 1;

SELECT uav_id, sender_state
FROM uav_communications
WHERE comm_id = 0;

SELECT uav_name, model, manufacturer
FROM uavs
WHERE max_altitude > (SELECT AVG(max_altitude) FROM uavs);

SELECT uav_name 
FROM uavs 
WHERE uav_id < 1 AND max_speed > 100;
